import React, { useState } from "react";

function CitizenDashboard() {
  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([]);

  const handleSend = () => {
    if (!message) return;

    const msg = message.toLowerCase();
    let reply = "";

    if (
      msg.includes("help") ||
      msg.includes("danger") ||
      msg.includes("unsafe") ||
      msg.includes("emergency") ||
      msg.includes("attack")
    ) {
      reply = "🚨 SOS ALERT SENT! Authorities Notified!";
    } else {
      reply = "✅ Complaint Registered!";
    }

    setChat([
      ...chat,
      { sender: "You", text: message },
      { sender: "AI", text: reply }
    ]);

    setMessage("");
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>AI Civic Assistant 🚀</h1>
      <p style={styles.subtitle}>Smart Complaint & SOS System</p>

      <div style={styles.chatBox}>
        {chat.length === 0 && (
          <p style={{ opacity: 0.5 }}>Start typing to report or trigger SOS...</p>
        )}

        {chat.map((msg, i) => (
          <div
            key={i}
            style={{
              ...styles.message,
              alignSelf: msg.sender === "You" ? "flex-end" : "flex-start",
              background:
                msg.sender === "You" ? "#00c6ff" : "#2a2a40",
            }}
          >
            <b>{msg.sender}</b>
            <div>{msg.text}</div>
          </div>
        ))}
      </div>

      <div style={styles.inputArea}>
        <input
          value={message}
          onChange={(e) => setMessage(e.target.value)}
          placeholder="Type complaint or SOS..."
          style={styles.input}
        />

        <button onClick={handleSend} style={styles.button}>
          Send
        </button>
      </div>
    </div>
  );
}

const styles = {
  container: {
    height: "100vh",
    background: "linear-gradient(135deg, #0f2027, #203a43, #2c5364)",
    color: "white",
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    padding: "20px",
    fontFamily: "sans-serif",
  },

  title: {
    marginBottom: "5px",
  },

  subtitle: {
    marginBottom: "20px",
    opacity: 0.7,
  },

  chatBox: {
    width: "100%",
    maxWidth: "600px",
    height: "350px",
    background: "rgba(255,255,255,0.05)",
    borderRadius: "10px",
    padding: "15px",
    overflowY: "auto",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  message: {
    padding: "10px",
    borderRadius: "10px",
    maxWidth: "70%",
  },

  inputArea: {
    marginTop: "15px",
    display: "flex",
    width: "100%",
    maxWidth: "600px",
    gap: "10px",
  },

  input: {
    flex: 1,
    padding: "10px",
    borderRadius: "8px",
    border: "none",
    outline: "none",
  },

  button: {
    padding: "10px 20px",
    borderRadius: "8px",
    border: "none",
    background: "#00c6ff",
    color: "black",
    fontWeight: "bold",
    cursor: "pointer",
  },
};

export default CitizenDashboard;
